                {"name": "alembic", "version": "1.12.1", "reason": "配套SQLAlchemy的数据库迁移工具"},
                {"name": "minio", "version": "7.2.3", "reason": "对象存储SDK，兼容S3协议"},
                {"name": "opentelemetry-sdk", "version": "1.21.0", "reason": "可观测埋点标准实现"},
                {"name": "import-linter", "version": "1.12.0", "reason": "自动化校验依赖边界，防止跨层违规调用"}
