            "node_packages": [],
            "system_requirements": ["libjpeg-dev（图像处理依赖）", "Docker & Docker Compose（部署依赖）"],
            "lock_rationale": "全部选择经过生产验证的LTS稳定版本，避免前沿版本的兼容性问题，仅在有明确功能/安全需求时才升级依赖，最小化依赖变更带来的风险。"
        },
        "architecture": {
            "modules": [
                {
                    "name": "Shared Kernel（核心共享层）",
                    "responsibility": "定义核心业务实体、通用业务规则（合规、VI、Logo叠加规则）、外部依赖抽象接口，无任何外部框架/服务依赖，是唯一的全局共享模块",
                    "dependencies": [],
                    "paradigm_influence": "边界防腐与高度解耦"
                },
                {
                    "name": "Image Generation Feature（核心生图垂直切片）",
                    "responsibility": "完整的生图全流程编排，包含参数校验、提示词优化、生图调用、合规审核、VI校验、Logo叠加全链路逻辑，自包含路由、工作流、测试代码",
                    "dependencies": ["Shared Kernel"],
                    "paradigm_influence": "垂直内聚与直觉实用 + 数据流转与状态驱动"
                },
                {
                    "name": "Skill Packaging Feature（Skill封装垂直切片）",
                    "responsibility": "将生图流程打包为可复用独立Skill，支持Skill的CRUD、独立调用、配置固化，自包含路由、服务、测试代码",
                    "dependencies": ["Shared Kernel", "Image Generation Feature（标准接口）"],
                    "paradigm_influence": "垂直内聚与直觉实用"
                },
                {
                    "name": "Infrastructure Layer（基础设施层）",
                    "responsibility": "实现Shared Kernel定义的抽象接口，包含生图API适配、内容审核服务适配、存储适配、第三方Skill接入适配，屏蔽外部依赖差异",
                    "dependencies": ["Shared Kernel"],
                    "paradigm_influence": "边界防腐与高度解耦"
                },
                {
                    "name": "Governance Feature（可观测治理垂直切片）",
                    "responsibility": "限流降级、健康检查、性能监控、告警、分布式追踪，独立于业务逻辑，可通过中间件/装饰器注入到业务流程中",
                    "dependencies": ["Shared Kernel"],
                    "paradigm_influence": "垂直内聚与直觉实用"
                }
            ],
            "data_flow": "用户请求 -> 路由层参数校验 -> 合规初审 -> 提交Temporal工作流（状态机驱动单向流转：提示词优化 -> 生图API调用 -> VI合规校验 -> Logo叠加 -> 二次内容审核 -> 结果存储） -> 立即返回任务ID -> 用户可通过轮询/SSE接口查询任务进度，工作流每个步骤的状态由Temporal持久化，失败自动按策略重试/补偿，最终结果通过回调/推送返回给用户。",
            "boundaries": [
                "核心边界：Shared Kernel仅依赖Python标准库，所有外部交互必须通过自身定义的抽象接口，禁止引入任何外部框架/服务依赖，由import-linter自动化校验",
                "垂直切片边界：每个Feature仅允许依赖Shared Kernel的抽象接口，禁止Feature之间直接调用内部实现，跨Feature调用必须通过Shared Kernel定义的标准接口",
                "状态边界：所有业务状态由Temporal工作流统一管理，禁止原地更新数据库状态，状态变化生成不可变事件记录，保证全链路可追溯"
            ],
            "feature_organization": "代码按业务Feature分包，每个Feature对应独立顶级目录，自包含路由、服务、工作流、测试、配置文件，新增Feature只需新建对应目录，几乎不需要修改已有代码，删除Feature直接移除对应目录即可，无隐式依赖。"
        },
        "directory_tree_manifest": [
            {
                "path": "/app",
                "module_id": "root",
                "permission": "read-write",
                "scene_compatible": ["所有场景"],
                "children": [
                    {
                        "path": "/app/shared",
                        "module_id": "module_0",
                        "permission": "read-only（仅核心开发者可修改）",
                        "scene_compatible": ["所有场景"]
                    },
                    {
                        "path": "/app/features/gen_image",
                        "module_id": "module_1",
                        "permission": "read-write",
                        "scene_compatible": ["生图业务场景"]
                    },
                    {
                        "path": "/app/features/skill_pack",
                        "module_id": "module_2",
                        "permission": "read-write",
                        "scene_compatible": ["Skill封装场景"]
                    },
                    {
                        "path": "/app/infra",
                        "module_id": "module_3",
                        "permission": "read-write",
                        "scene_compatible": ["外部依赖适配场景"]
                    },
                    {
                        "path": "/app/features/governance",
                        "module_id": "module_4",
                        "permission": "read-write",
                        "scene_compatible": ["可观测治理场景"]
                    },
                    {
                        "path": "/app/tests",
                        "module_id": "test",
                        "permission": "read-write",
                        "scene_compatible": ["测试场景"]
                    }
                ]
            }
        ],
        "data_structures": [
            {
                "name": "GenImageRequest",
                "fields": [
                    {"name": "request_id", "type": "string", "description": "请求唯一ID"},
                    {"name": "user_id", "type": "string", "description": "用户ID"},
                    {"name": "prompt", "type": "string", "description": "用户输入提示词"},
                    {"name": "size", "type": "string", "description": "生成图片尺寸"},
                    {"name": "brand_id", "type": "string|None", "description": "品牌ID，用于获取VI/Logo配置"},
                    {"name": "skill_id", "type": "string|None", "description": "关联Skill ID"}
                ]
            },
            {
                "name": "TaskState",
                "fields": [
                    {"name": "task_id", "type": "string", "description": "全局唯一任务ID"},
                    {"name": "status", "type": "enum", "description": "任务状态：PENDING/TEXT_PASSED/PROMPT_GENERATED/IMAGE_GENERATED/VI_PASSED/LOGO_ADDED/COMPLETED/FAILED"},
